class MetricsCollector:
    def __init__(self):
        self._metrics = {}

    def set_metric(self, name: str, value):
        """
        Sets the value of a custom metric.
        If a metric with the given name already exists, its value is updated.
        """
        self._metrics[name] = value

    def get_metric(self, name: str):
        """
        Retrieves the value of a specific metric by its name.
        Returns None if the metric does not exist.
        """
        return self._metrics.get(name)

    def get_all_metrics(self) -> dict:
        """
        Retrieves all collected metrics as a dictionary.
        Returns a copy of the internal metrics dictionary to prevent external modification.
        """
        return self._metrics.copy()

    def clear_metrics(self):
        """
        Clears all collected metrics from the collector.
        """
        self._metrics.clear()
